__global__ void nw_block_kernel(int *input_itemsets, int *referrence, int max_cols, int penalty, int blk, int max_rows, int max_cols_global)
{
    int b_index_x = blockIdx.x;
    int b_index_y = blk - 1 - b_index_x;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    int base_ref_y = b_index_y * BLOCK_SIZE + 1;
    int base_ref_x = b_index_x * BLOCK_SIZE + 1;

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i * BLOCK_SIZE + j] = referrence[max_cols_global * (base_ref_y + i) + (base_ref_x + j)];
        }
    }

    int base_in_y = b_index_y * BLOCK_SIZE;
    int base_in_x = b_index_x * BLOCK_SIZE;

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols_global * (base_in_y + i) + (base_in_x + j)];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols_global * (base_ref_y + i) + (base_ref_x + j)] = input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

__global__ void nw_block_kernel_bottom(int *input_itemsets, int *referrence, int max_cols, int penalty, int blk, int max_rows, int max_cols_global, int total_blocks)
{
    int b_index_x = blockIdx.x;
    int b_index_y = total_blocks + blk - 2 - b_index_x;

    if (b_index_x < blk - 1 || b_index_x >= total_blocks) return;
    if (b_index_y < 0 || b_index_y >= total_blocks) return;

    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

    int base_ref_y = b_index_y * BLOCK_SIZE + 1;
    int base_ref_x = b_index_x * BLOCK_SIZE + 1;

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            reference_l[i * BLOCK_SIZE + j] = referrence[max_cols_global * (base_ref_y + i) + (base_ref_x + j)];
        }
    }

    int base_in_y = b_index_y * BLOCK_SIZE;
    int base_in_x = b_index_x * BLOCK_SIZE;

    for (int i = 0; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 0; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = input_itemsets[max_cols_global * (base_in_y + i) + (base_in_x + j)];
        }
    }

    for (int i = 1; i < BLOCK_SIZE + 1; ++i) {
        for (int j = 1; j < BLOCK_SIZE + 1; ++j) {
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = maximum(
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
        }
    }

    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            input_itemsets[max_cols_global * (base_ref_y + i) + (base_ref_x + j)] = input_itemsets_l[(i + 1) * (BLOCK_SIZE + 1) + j + 1];
        }
    }
}

void nw_optimized(int *input_itemsets, int *output_itemsets, int *referrence,
        int max_rows, int max_cols, int penalty)
{
    int total_blocks = (max_cols - 1) / BLOCK_SIZE;

    int *d_input_itemsets;
    int *d_referrence;

    size_t size = max_rows * max_cols * sizeof(int);

    cudaMalloc(&d_input_itemsets, size);
    cudaMalloc(&d_referrence, size);

    cudaMemcpy(d_input_itemsets, input_itemsets, size, cudaMemcpyHostToDevice);
    cudaMemcpy(d_referrence, referrence, size, cudaMemcpyHostToDevice);

    for (int blk = 1; blk <= total_blocks; blk++) {
        int num_blocks = blk;
        nw_block_kernel<<<num_blocks, 1>>>(d_input_itemsets, d_referrence, max_cols, penalty, blk, max_rows, max_cols);
        cudaDeviceSynchronize();
    }

    printf("Processing bottom-right matrix\n");

    for (int blk = 2; blk <= total_blocks; blk++) {
        int start_x = blk - 1;
        int num_blocks = total_blocks - start_x;
        if (num_blocks > 0) {
            nw_block_kernel_bottom<<<num_blocks, 1>>>(d_input_itemsets, d_referrence, max_cols, penalty, blk, max_rows, max_cols, total_blocks);
            cudaDeviceSynchronize();
        }
    }

    cudaMemcpy(input_itemsets, d_input_itemsets, size, cudaMemcpyDeviceToHost);

    cudaFree(d_input_itemsets);
    cudaFree(d_referrence);
}

